```bash
cd ./llvm && cat > /tmp/fix.patch << 'EOF' && patch -p1 < /tmp/fix.patch
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4733,6 +4733,11 @@ static Value *simplifySelectWithICmpCond(Value *CondVal, Value *TrueVal,
   // If we have a scalar equality comparison, then we know the value in one of
   // the arms of the select. See if substituting this value into the arm and
   // simplifying the result yields the same value as the other arm.
   if (Pred == ICmpInst::ICMP_EQ) {
+    // For pointer types, icmp eq does not guarantee that the pointers are
+    // identical due to provenance, so we cannot safely substitute unless at
+    // least one operand is a constant.
+    if (CmpLHS->getType()->isPtrOrPtrVectorTy() && !isa<Constant>(CmpLHS) &&
+        !isa<Constant>(CmpRHS))
+      return nullptr;
     if (Value *V = simplifySelectWithEquivalence({{CmpLHS, CmpRHS}}, TrueVal,
                                                  FalseVal, Q, MaxRecurse))
       return V;
EOF
